const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const path = require('path');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"]
  }
});

// Раздаем статику из текущей папки
app.use(express.static(__dirname));

// Хранилище состояния игры
let scores = {
  red: 0,
  blue: 0
};

io.on('connection', (socket) => {
  console.log('Игрок подключился:', socket.id);

  // Отправляем текущий счет новому игроку
  socket.emit('updateScores', scores);

  // Обработка клика
  socket.on('click', (team) => {
    if (scores[team] !== undefined) {
      scores[team]++;
      // Рассылаем обновленный счет всем
      io.emit('updateScores', scores);

      // Анимация клика для всех
      io.emit('clickEffect', { team });
    }
  });

  socket.on('disconnect', () => {
    console.log('Игрок отключился:', socket.id);
  });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`Сервер запущен на порту ${PORT}`);
});

